export function seedNatoCyber(db) {
    console.log('  Seeding NATO cyber defence policy...');
    const insertSource = db.prepare(`INSERT INTO sources (title, short_title, source_type, organization, adoption_date, entry_into_force_date, status, signatories_count, url, notes)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`);
    const insertArticle = db.prepare(`INSERT INTO articles (source_id, article_number, title, content, chapter, part, keywords)
     VALUES (?, ?, ?, ?, ?, ?, ?)`);
    const result = insertSource.run('NATO Cyber Defence Policy and Summit Declarations', 'NATO Cyber Defence Policy', 'policy', 'North Atlantic Treaty Organization (NATO)', '2014-09-05', null, 'in_force', 32, 'https://www.nato.int/cps/en/natohq/topics_78170.htm', 'NATO Enhanced Cyber Defence Policy adopted at Wales Summit 2014. Cyberspace recognized as operational domain at Warsaw Summit 2016. Updated at Brussels (2018, 2021), Madrid (2022), and Vilnius (2023) summits.');
    const srcId = Number(result.lastInsertRowid);
    const articles = [
        // Wales Summit 2014
        { num: 'Wales 2014 - Para 72', title: 'Cyber defence as part of collective defence', content: 'We have endorsed an Enhanced Cyber Defence Policy, contributing to the fulfillment of the Alliance\'s core tasks. The policy establishes that cyber defence is part of NATO\'s core task of collective defence. A decision as to when a cyber attack would lead to the invocation of Article 5 would be taken by the North Atlantic Council on a case-by-case basis.', ch: 'Wales Summit Declaration 2014', part: null, kw: 'collective defence,Article 5,cyber attack,case-by-case,Enhanced Policy' },
        { num: 'Wales 2014 - Para 73', title: 'International law applies to cyberspace', content: 'We affirm that international law, including international humanitarian law and the UN Charter, applies in cyberspace. Cyber attacks can reach a threshold that threatens national and Euro-Atlantic prosperity, security and stability. Their impact could be as harmful to modern societies as a conventional attack.', ch: 'Wales Summit Declaration 2014', part: null, kw: 'international law,IHL,UN Charter,threshold,conventional attack' },
        // Warsaw Summit 2016
        { num: 'Warsaw 2016 - Para 70', title: 'Cyberspace as operational domain', content: 'We recognise cyberspace as a domain of operations in which NATO must defend itself as effectively as it does in the air, on land, and at sea. This will not change the Alliance\'s mission or mandate, which is defensive in nature, and will not change applicable law.', ch: 'Warsaw Summit Communique 2016', part: null, kw: 'operational domain,fifth domain,air land sea,defensive mandate' },
        { num: 'Warsaw 2016 - Para 71', title: 'Cyber Defence Pledge', content: 'We have made a Cyber Defence Pledge to enhance the cyber defences of our national networks and infrastructure, as a matter of priority. Each Ally will commit the necessary resources, skills and capabilities to develop its national cyber defence capacity, including through the implementation of NATO\'s Cyber Defence Policy.', ch: 'Warsaw Summit Communique 2016', part: null, kw: 'Cyber Defence Pledge,national capacity,resources,skills' },
        // Brussels 2018
        { num: 'Brussels 2018 - Para 20', title: 'Sovereign cyber effects from Allies', content: 'We have agreed that NATO can draw on national cyber capabilities for its missions and operations. Allies have committed, on a voluntary basis, to integrate sovereign cyber effects, provided voluntarily by Allies, into Alliance operations and missions, in the framework of strong political oversight.', ch: 'Brussels Summit Declaration 2018', part: null, kw: 'sovereign cyber effects,voluntary,political oversight,operations' },
        // Brussels 2021
        { num: 'Brussels 2021 - Para 32', title: 'Comprehensive Cyber Defence Policy', content: 'We have endorsed a new Comprehensive Cyber Defence Policy, which will support NATO\'s three core tasks of collective defence, crisis management and cooperative security, as well as its overall deterrence and defence posture. We reaffirm that a decision as to when a cyber attack would lead to the invocation of Article 5 would be taken by the North Atlantic Council on a case-by-case basis. Allies recognise that the impact of significant malicious cumulative cyber activities might, in certain circumstances, be considered as amounting to an armed attack.', ch: 'Brussels Summit Communique 2021', part: null, kw: 'Comprehensive Policy,three core tasks,cumulative cyber activities,armed attack' },
        { num: 'Brussels 2021 - Para 33', title: 'Attribution and response', content: 'We acknowledge that significant malicious cyber activities could constitute a clear breach of international obligations that, in certain circumstances, could be considered as amounting to an armed attack. We are determined to employ the full range of capabilities at all times to actively deter, defend against, and counter the full spectrum of cyber threats, including those conducted as part of hybrid campaigns.', ch: 'Brussels Summit Communique 2021', part: null, kw: 'attribution,response options,full spectrum,hybrid,deterrence' },
        // Madrid 2022
        { num: 'Madrid 2022 - Para 10', title: 'Strategic Concept — cyber threats', content: 'Cyberspace is contested at all times. Malicious cyber actors seek to degrade our critical infrastructure, interfere with our government services, extract intelligence, steal intellectual property and impede our military activities. The increasing use of cyber tools and methods by State and non-State actors to achieve strategic and political goals, including those designed to disrupt, damage or destroy our critical national infrastructure and digital government services, shows that cyberspace is a real domain of conflict.', ch: 'NATO Strategic Concept 2022', part: null, kw: 'Strategic Concept,contested,critical infrastructure,domain of conflict' },
        { num: 'Madrid 2022 - Para 25', title: 'NATO Cyber Defence Centre', content: 'We will further develop our cyber capabilities, including through the enhanced NATO Cyber Defence Centre, to protect our networks, and strengthen our military cyber defences, including by adopting new technologies.', ch: 'NATO Strategic Concept 2022', part: null, kw: 'Cyber Defence Centre,capabilities,new technologies' },
        // Vilnius 2023
        { num: 'Vilnius 2023 - Para 51', title: 'Virtual Cyber Incident Support Capability', content: 'We have launched a new virtual Cyber Incident Support Capability (VCISC) to support national mitigation efforts and to help Allies respond to significant malicious cyber activities.', ch: 'Vilnius Summit Communique 2023', part: null, kw: 'VCISC,incident support,mitigation,response capability' },
        { num: 'Vilnius 2023 - Para 52', title: 'Cyber defence and AI', content: 'We will enhance our cyber defences through increased cooperation and information sharing. We acknowledge the potential of artificial intelligence to enhance our cyber defence capabilities, while recognizing the associated risks.', ch: 'Vilnius Summit Communique 2023', part: null, kw: 'AI,artificial intelligence,information sharing,cyber defence enhancement' },
        // CCDCOE
        { num: 'CCDCOE', title: 'NATO Cooperative Cyber Defence Centre of Excellence', content: 'The NATO Cooperative Cyber Defence Centre of Excellence (CCDCOE), established in Tallinn, Estonia in 2008, is a NATO-accredited centre of excellence conducting interdisciplinary cyber defence research, training and exercises. Key outputs include the Tallinn Manual series, Locked Shields (world\'s largest live-fire cyber defence exercise), and CyCon (annual International Conference on Cyber Conflict). The Centre has 39 contributing nations.', ch: 'Institutions', part: null, kw: 'CCDCOE,Tallinn,Estonia,Locked Shields,CyCon,research,training' },
        { num: 'NICP', title: 'NATO Industry Cyber Partnership', content: 'The NATO Industry Cyber Partnership (NICP), launched in 2014, provides a framework for cooperation between NATO and the private sector on cyber defence. It brings together government, military, academic and industry expertise. The NICP is a key component of NATO\'s effort to address evolving cyber threats through public-private partnerships.', ch: 'Institutions', part: null, kw: 'NICP,industry partnership,private sector,public-private' },
    ];
    const insertMany = db.transaction(() => {
        for (const art of articles) {
            insertArticle.run(srcId, art.num, art.title, art.content, art.ch, art.part, art.kw);
        }
    });
    insertMany();
    console.log(`    NATO Cyber Defence: ${articles.length} articles`);
}
